/**
 * 将写死的文本转换为系统通用的 JSON 数组结构
 */
const parseTSV = (tsv: string) => {
  const lines = tsv.trim().split('\n');
  if (lines.length < 2) return [];
  
  // 兼容制表符或连续空格作为分隔符
  const separator = lines[0].includes('\t') ? '\t' : (lines[0].includes('  ') ? /\s{2,}/ : ' ');
  const headers = lines[0].split(separator).map(h => h.trim());
  
  return lines.slice(1).map(line => {
    const values = line.split(separator);
    const obj: any = {};
    headers.forEach((h, i) => {
      obj[h] = values[i] ? values[i].trim() : '';
    });
    return obj;
  });
};

export function getSampleRawRows() {
  const rows1 = parseTSV(dataApril);
  const rows2 = parseTSV(dataMayJune);
  return [...rows1, ...rows2];
}
